logger = logging.getLogger()
logger.setLevel(logging.INFO)

s3_client = boto3.client('s3')
sns_client = boto3.client('sns')

def lambda_handler(event, context):
    bucket = event['Records'][0]['s3']['bucket']['name']
    key = event['Records'][0]['s3']['object']['key']
    
    try:
        # Read image from S3
        response = s3_client.get_object(Bucket=bucket, Key=key)
        image = Image.open(response['Body'])
        
        # Process image (example: convert to grayscale)
        processed_image = image.convert('L')
        
        # Save processed image to S3
        buffer = BytesIO()
        processed_image.save(buffer, 'JPEG')
        buffer.seek(0)
        s3_client.put_object(Bucket=bucket, Key=f'processed/{key}', Body=buffer)
        
        # Send notification via SNS
        sns_client.publish(
            TopicArn='arn:aws:sns:REGION:ACCOUNT_ID:YOUR_TOPIC',
            Message=f'Image {key} has been processed and saved to processed/{key}',
            Subject='Image Processing Notification'
        )
        
        logger.info(f'Successfully processed image: {key}')
        
    except Exception as e:
        logger.error(f'Error processing image {key}: {str(e)}')
        raise e

    return {
        'statusCode': 200,
        'body': json.dumps('Image processed successfully')
    }